import * as React from "react";
import { connect } from "react-redux";
import { RouteComponentProps, withRouter } from "react-router";
import { Modal, Upload, Button, Select, Progress, message } from 'antd';
import { Modal_Audio_Convert } from '../../constants/ModalNames';
import { updateModalName } from "../../actions/editorActions";
import { timeToSeconds } from "../../utils/timeToSeconds";
import { deepClone } from './../../utils/deepClone';
import { addHTMLElementStyle } from "../../utils/addStyle";
import { formatMessage } from "../../AppRouter";

const { Dragger } = Upload;

interface IState {
    /**
     * 需要转换的文件
     */
    inputFiles: File[];
    /**
     * 输出文件列表
     */
    outputFiles: any;
    /**
     * 当前正在转换的文件索引
     */
    converFileIndex: number;
    /**
     * 是否已经开始转换
     */
    isStarted: boolean;
    /**
     * 输出格式
     */
    format: string|undefined;
    /**
     * 编码器
     */
    encoder: string|undefined;
    /**
     * 质量
     */
    abitrate: string|undefined;
    /**
     * 采样率
     */
    asample: number;
    /**
     * 通道
     */
    achannels: number;
    /**
     * 输出信息
     */
    outputInfo: string|undefined;
}

interface IProps extends RouteComponentProps<any> {
    currentModalName: string|undefined;
    mainDockPanelStyle: any;
    updateModalName: Function;
}

const mapStateToProps = (state: any) => {
    return {
        currentModalName: state.editor.currentModalName,
        mainDockPanelStyle: state.setting.mainDockPanelStyle
    }
};

const mapDispatchTpProps = {
    updateModalName
};

const audioConfig: any = {
    MP3: {
        encoder : ['libmp3lame'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    WAV: {
        encoder : ['pcm_s16le'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    OGG: {
        encoder : ['flac'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    AAC: {
        encoder : ['aac'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    M4A: {
        encoder : ['alac'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    M4R: {
        encoder : ['aac'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    FLAC: {
        encoder : ['flac'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    WMA: {
        encoder : ['wmav1', 'wmav2'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    OPUS: {
        encoder : ['libopus'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 12000, 16000, 48000],
        achannels: ['Mono', 'Stereo']
    },
    AIFF: {
        encoder : ['pcm_s16be'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [8000, 11025, 12000, 16000, 22050, 24000, 32000, 44100, 48000],
        achannels: ['Mono', 'Stereo']
    },
    MMF: {
        encoder : ['adpcm_yamaha'],
        abitrate: ['48k', '64k', '80k', '96k', '128k', '160k', '256k'],
        asample: [44100, 22050, 11025, 8000, 4000],
        achannels: ['Mono', 'Stereo']
    }
};

class AudioConvertModal extends React.Component<IProps, IState> {

    private worker: Worker|null;
    private outputFiles: any;
    private modalRootContainer: any;

    constructor(props: IProps) {
        super(props);
        this.worker = null;
        this.outputFiles = {};
        this.state = {
            inputFiles: [],
            outputFiles: {},
            converFileIndex: 0,
            isStarted: false,
            format: 'MP3',
            encoder: 'libmp3lame',
            abitrate: '128k',
            asample: 44100,
            achannels: 1,
            outputInfo: undefined
        };
    }
    
    handleCancel = () => {
        this.props.updateModalName(null);
        this.worker = null;
        this.outputFiles = {};
        this.setState({
            inputFiles: [],
            isStarted: false,
            format: 'MP3',
            encoder: 'libmp3lame',
            abitrate: '128k',
            asample: 44100,
            achannels: 1,
            outputInfo: undefined
        });
    };

    handleFormatChange = (format: string) => {

        this.setState({
            format,
            encoder: audioConfig[format].encoder[0]
        });
    };

    handleEncoderChange = (encoder: string) => {
        this.setState({
            encoder
        });
    };

    handleAbitrateChange = (abitrate: string) => {
        this.setState({
            abitrate
        });
    };

    handleAsampleChange = (asample: number) => {
        this.setState({
            asample
        });
    };

    handleAchannelsChange = (achannels: number) => {
        this.setState({
            achannels
        });
    };

    handleStartConvert = () => {
        if (this.state.converFileIndex < this.state.inputFiles.length) {
            if (this.worker == null) {
                this.worker = new Worker(`${process.env.PUBLIC_URL}/assets/libs/auido_worker.js`);
            }
            if (this.state.converFileIndex == 0) {
                this.setState({
                    outputInfo: formatMessage({id: 'app.init'}) + "..."
                });
            }
            let file = this.state.inputFiles[this.state.converFileIndex];
            this.audioConvert(file);
        } else {
            this.setState({
                outputInfo: formatMessage({id: 'app.convert'}),
                isStarted: false
            });
        }
    };

    audioConvert = (file: any) => {
        if (file) {
            let fileReader = new FileReader();
            fileReader.onload = (e) => {
                this.setState({
                    outputInfo: formatMessage({id: 'app.converting'}) + "..."
                });
                if (this.worker) {
                    let win = window as any;
                    let durationRegx = /Duration: (.*?), /;
                    let timeRegx = /time=(.*?) /;
                    let duration: number = 0;
                    this.worker.onmessage = (e: any) => {
                        if ("ready" === e.data.type && win.File && win.FileList && win.FileReader) {

                        } else if ("stdout" == e.data.type) {
                            // console.log(e.data.data);
                        } else if ("stderr" == e.data.type) {
                            // console.log(e.data.data);
                            let dResult = durationRegx.exec(e.data.data), tResult = timeRegx.exec(e.data.data);
                            if (dResult) {
                                duration = timeToSeconds(dResult[1]);
                            }
                            if (tResult) {
                                let time = timeToSeconds(tResult[1]);
                                if (duration) {
                                    let progress = Math.floor(time / duration * 100);
                                    let file: any = this.state.inputFiles[this.state.converFileIndex];
                                    if (file) {
                                        const outputFiles = deepClone(this.state.outputFiles);
                                        const outputFile = outputFiles[file.uid];
                                        if (outputFile) {
                                            outputFile.progress = progress;
                                        } else {
                                            outputFiles[file.uid] = {progress};
                                        }
                                        this.setState({
                                            outputFiles
                                        });
                                    }
                                }
                            }
                        } else if ("done" == e.data.type) {
                            let outputFiles = e.data.data;
                            if (outputFiles.length > 0 && outputFiles[0].data.byteLength > 0) {
                                let outputFileName = outputFiles[0].name;
                                let outputFileData = outputFiles[0].data;
                                let file: any = this.state.inputFiles[this.state.converFileIndex];
                                if (file) {
                                    this.outputFiles[outputFileName] = outputFileData;
                                    const outputFiles = deepClone(this.state.outputFiles);
                                    const outputFile = outputFiles[file.uid];
                                    if (outputFile) {
                                        outputFile.name = outputFileName;
                                    } else {
                                        outputFiles[file.uid] = {
                                            name: outputFileName,
                                            progress: 100
                                        };
                                    }
                                    this.setState({
                                        outputFiles
                                    });
                                }
                            }
                            this.setState({
                                converFileIndex: this.state.converFileIndex + 1
                            });
                            this.handleStartConvert();
                        }
                    };
                }

                const outputFiles = deepClone(this.state.outputFiles);
                if (!outputFiles[file.uid]) {
                    outputFiles[file.uid] = {
                        progress: 0,
                        name: null,
                        data: null
                    }
                }
                this.setState({
                    outputFiles
                });
                const inputFile = "input." + file.name.split(".").pop();
                const outputBaseName = file.name.split(".")[0];
                const args = [];
                args.push("-i");
                args.push(inputFile);
                if (this.state.abitrate) {
                    args.push("-ab");
                    args.push(this.state.abitrate);
                }
                if (this.state.asample) {
                    args.push("-ar");
                    args.push(this.state.asample);
                }
                if (this.state.achannels) {
                    args.push("-ac");
                    args.push(this.state.achannels);
                }
                let format = this.state.format ? this.state.format.toLowerCase() : '';
                switch(format) {
                    case "mp3":
                        args.push("-acodec");
                        args.push("libmp3lame");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).mp3`));
                        break;
                    case "ogg":
                        args.push("-acodec");
                        if (this.state.encoder) {
                            args.push(this.state.encoder);
                            if (this.state.encoder == 'vorbis') {
                                args.push("-strict");
                                args.push("-2");
                            }
                        } else {
                            args.push("flac");
                        }
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).ogg`));
                        break;
                    case "aac":
                        args.push("-acodec");
                        if (this.state.encoder) {
                            args.push(this.state.encoder);
                        } else {
                            args.push("aac");
                        }
                        args.push("-f");
                        args.push("mp4");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).aac`));
                        break;
                    case "wma":
                        args.push("-acodec");
                        if (this.state.encoder) {
                            args.push(this.state.encoder);
                        } else {
                            args.push("wmav1");
                        }
                        args.push("-f");
                        args.push("asf");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).wma`));
                        break;
                    case "wav":
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).wav`));
                        break;
                    case "m4a":
                        args.push("-acodec");
                        if (this.state.encoder) {
                            args.push(this.state.encoder);
                        } else {
                            args.push("aac");
                        }
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).m4a`));
                        break;
                    case "m4r":
                        args.push("-acodec");
                        args.push("aac");
                        args.push("-f");
                        args.push("ipod");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).m4r`));
                        break;
                    case "flac":
                        args.push("-acodec");
                        args.push("flac");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).flac`));
                        break;
                    case "opus":
                        args.push("-acodec");
                        args.push("libopus");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).opus`));
                        break;
                    case "aiff":
                        args.push("-acodec");
                        args.push("pcm_s16be");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).aiff`));
                        break;
                    case "mmf":
                        args.push("-acodec");
                        args.push("adpcm_yamaha");
                        args.push("-strict");
                        args.push("-2");
                        args.push(this.getOutputFileName(`${outputBaseName}(www.zanejs.com).mmf`));
                        break;
                }
                this.worker && this.worker.postMessage({
                    type: "command",
                    arguments: args,
                    files: [{
                        name: inputFile,
                        data: new Uint8Array(fileReader.result as any)
                    }]
                });
            }
            fileReader.readAsArrayBuffer(file);
        } else {
            this.setState({
                converFileIndex: this.state.converFileIndex + 1
            });
            this.handleStartConvert();
        }
    };

    getOutputFileName = (fileName: string) => {
        let zanejs = (window as any).zanejs;
        let result = fileName;
        let extensions = "." + result.split(".").pop();
        while(this.outputFiles[result]) {
            result = `${zanejs.utils.basename(result, extensions)}(1)${extensions}`;
        }
        return result;
    };

    generateEncoderOption = () => {
        let format: string = this.state.format || 'MP3';
        let encoders = audioConfig[format].encoder;
        return encoders.map((encoder: string, i: number) => {
            return(<Select.Option value={encoder} key = {i}>{encoder}</Select.Option>);
        });
    };

    generateAbitrateOption = () => {
        let format: string = this.state.format || 'MP3';
        let abitrates = audioConfig[format].abitrate;
        return abitrates.map((abitrate: string, i: number) => {
            return(<Select.Option value={abitrate} key = {i}>{abitrate}</Select.Option>);
        });
    };

    generateAsampleOption = () => {
        let format: string = this.state.format || 'MP3';
        let asamples = audioConfig[format].asample;
        return asamples.map((asample: number, i: number) => {
            return(<Select.Option value={asample} key = {i}>{asample}</Select.Option>);
        });
    };

    generateAchannelsOption = () => {
        let format: string = this.state.format || 'MP3';
        let achannels = audioConfig[format].achannels;
        return achannels.map((achannel: number, i: number) => {
            return(<Select.Option value={i + 1} key = {i}>{achannel}</Select.Option>);
        });
    };

    _addHTMLElementStyle = () => {
        if (this.modalRootContainer) {
            addHTMLElementStyle(this.modalRootContainer, "modal-root-container::before", this.props.mainDockPanelStyle);
        } else {
            setTimeout(this._addHTMLElementStyle, 500);
        }
    };

    componentDidMount(): void {
        this._addHTMLElementStyle();
    }

    render() {
        let visible: boolean = this.props.currentModalName == Modal_Audio_Convert;
        let win = window as any;
        let browserSupported = win.File && win.FileReader && win.FileList && win.Blob;
        let modalWidth = 900;
        return (
            <Modal
                width={modalWidth}
                wrapClassName="editor-modal-wrap"
                title={<span>{formatMessage({id: 'app.audioConvert'})}</span>}
                footer={null}
                visible={visible}
                onCancel={this.handleCancel}
                maskClosable={false}
                zIndex={999}>
                <div className="audio-convert-container modal-root-container" ref={(value) => this.modalRootContainer = value}>
                    <div className="top"></div>
                    <div className="middle">
                        <div style={{width: modalWidth - 20}}>
                            <div className="loadfile" style={{width: modalWidth - 30, margin: 5}}>
                            {
                                browserSupported 
                                ? (
                                    <Dragger 
                                        name='file' 
                                        multiple={false} 
                                        showUploadList={false}
                                        beforeUpload={(file, fileList) =>{
                                            let isHave = false;
                                            for (let i = 0, l = this.state.inputFiles.length; i < l; ++i) {
                                                const $file = this.state.inputFiles[i];
                                                if (file.name == $file.name && file.size == $file.size) {
                                                    isHave = true;
                                                }
                                            }
                                            if (!isHave) {
                                                const inputFiles = [...this.state.inputFiles];
                                                inputFiles.push(file);
                                                this.setState({
                                                    inputFiles
                                                });

                                            }
                                            return false;
                                        }}>
                                        <p>{formatMessage({id: 'app.clickOrDragTheFileHere'})}</p>
                                    </Dragger>
                                )
                                : (
                                    <p>{formatMessage({id: 'app.browserNotSupportH5'})}</p>
                                )
                            }
                            </div>
                        </div>
                        {
                            this.state.inputFiles.length > 0 && (
                                <div className="inputFile-list">
                                    {
                                        this.state.inputFiles.map((inputFile: any, index: number) => {
                                            let outputFile = this.state.outputFiles[inputFile.uid];
                                            let convertProgress, downloadUrl, downloadName, downloadSize, outputFileData;
                                            if (outputFile) {
                                                convertProgress = outputFile.progress;
                                                if (outputFile.name) {
                                                    downloadName = outputFile.name;
                                                    outputFileData = this.outputFiles[downloadName];
                                                    if (outputFileData) {
                                                        downloadSize =  (outputFileData.byteLength / 1024 / 1024).toFixed(2).toString();
                                                        downloadUrl = window.URL.createObjectURL(new Blob([outputFileData]));
                                                    }
                                                }
                                            }
                                            return (
                                                <div key={index}>
                                                    <span>
                                                        <div className="inputFile-list-item">
                                                            <div className="inputFile-list-item-info">
                                                                <span>
                                                                    <div className="item-icon">
                                                                        <span className="anticon">
                                                                            <svg viewBox="64 64 896 896" focusable="false" data-icon="paper-clip" width="1em" height="1em" fill="currentColor" aria-hidden="true">
                                                                                <path d="M779.3 196.6c-94.2-94.2-247.6-94.2-341.7 0l-261 260.8c-1.7 1.7-2.6 4-2.6 6.4s.9 4.7 2.6 6.4l36.9 36.9a9 9 0 0012.7 0l261-260.8c32.4-32.4 75.5-50.2 121.3-50.2s88.9 17.8 121.2 50.2c32.4 32.4 50.2 75.5 50.2 121.2 0 45.8-17.8 88.8-50.2 121.2l-266 265.9-43.1 43.1c-40.3 40.3-105.8 40.3-146.1 0-19.5-19.5-30.2-45.4-30.2-73s10.7-53.5 30.2-73l263.9-263.8c6.7-6.6 15.5-10.3 24.9-10.3h.1c9.4 0 18.1 3.7 24.7 10.3 6.7 6.7 10.3 15.5 10.3 24.9 0 9.3-3.7 18.1-10.3 24.7L372.4 653c-1.7 1.7-2.6 4-2.6 6.4s.9 4.7 2.6 6.4l36.9 36.9a9 9 0 0012.7 0l215.6-215.6c19.9-19.9 30.8-46.3 30.8-74.4s-11-54.6-30.8-74.4c-41.1-41.1-107.9-41-149 0L463 364 224.8 602.1A172.22 172.22 0 00174 724.8c0 46.3 18.1 89.8 50.8 122.5 33.9 33.8 78.3 50.7 122.7 50.7 44.4 0 88.8-16.9 122.6-50.7l309.2-309C824.8 492.7 850 432 850 367.5c.1-64.6-25.1-125.3-70.7-170.9z"></path>
                                                                            </svg>
                                                                        </span>
                                                                    </div>
                                                                    <span className="item-name">{inputFile.name}</span>
                                                                    <span className="item-actions">
                                                                        {
                                                                            outputFileData 
                                                                            ? <a download={downloadName} href={downloadUrl}>{formatMessage({id: 'app.save'})}({downloadSize}M)</a>
                                                                            : this.state.isStarted ?  '' : (<Button ghost={true} size="small">{formatMessage({id: 'app.delete'})}</Button>)
                                                                        }
                                                                    </span>
                                                                </span>
                                                            </div>
                                                            {
                                                                !outputFileData && convertProgress > 0 && <div className="inputFile-list-item-progress">
                                                                    <Progress showInfo={false} size="small" percent={convertProgress} />
                                                                </div>
                                                            }
                                                        </div>
                                                    </span>
                                                </div>
                                            );
                                        })
                                    }
                                </div>
                            )
                        }
                    </div>
                    <div className="middle">
                        <p>{formatMessage({id: 'app.outputFileFormat'})}</p>
                        <div className="button-group" style={{marginBottom: 30}}>
                            {
                                Object.keys(audioConfig).map((f, index) => {
                                    return (
                                    <div 
                                        key={index} 
                                        className={this.state.format == f ? 'active' : ''}
                                        onClick={() => {
                                            this.handleFormatChange(f);
                                        }}>
                                        {f}
                                    </div>)
                                })
                            }
                        </div>
                    </div>
                    <div className="middle">
                        <div className="convertParam-item">
                            <div className="convertParam-item-left">
                                <span>{formatMessage({id: 'app.encoder'})}</span>
                            </div>
                            <div className="convertParam-item-right">
                                <Select
                                    value={this.state.encoder} 
                                    onChange={this.handleEncoderChange}
                                    style={{width: '100%'}}
                                    dropdownMatchSelectWidth={false}
                                    className="editor-select"
                                    dropdownClassName="editor-select-dropdown" >
                                    {this.generateEncoderOption()}
                                </Select>
                            </div>
                        </div>
                        <div className="convertParam-item">
                            <div className="convertParam-item-left">
                                <span>{formatMessage({id: 'app.quality'})}</span>
                            </div>
                            <div className="convertParam-item-right">
                                <Select
                                    value={this.state.abitrate} 
                                    onChange={this.handleAbitrateChange}
                                    style={{width: '100%'}}
                                    dropdownMatchSelectWidth={false}
                                    className="editor-select"
                                    dropdownClassName="editor-select-dropdown" >
                                    {this.generateAbitrateOption()}
                                </Select>
                            </div>
                        </div>
                        <div className="convertParam-item">
                            <div className="convertParam-item-left">
                                <span>{formatMessage({id: 'app.samplingRate'})}</span>
                            </div>
                            <div className="convertParam-item-right">
                                <Select
                                    value={this.state.asample} 
                                    onChange={this.handleAsampleChange}
                                    style={{width: '100%'}}
                                    dropdownMatchSelectWidth={false}
                                    className="editor-select"
                                    dropdownClassName="editor-select-dropdown" >
                                    {this.generateAsampleOption()}
                                </Select>
                            </div>
                        </div>
                        <div className="convertParam-item">
                            <div className="convertParam-item-left">
                                <span>{formatMessage({id: 'app.channel'})}</span>
                            </div>
                            <div className="convertParam-item-right">
                                <Select
                                    value={this.state.achannels} 
                                    onChange={this.handleAchannelsChange}
                                    style={{width: '100%'}}
                                    dropdownMatchSelectWidth={false}
                                    className="editor-select"
                                    dropdownClassName="editor-select-dropdown" >
                                    {this.generateAchannelsOption()}
                                </Select>
                            </div>
                        </div>
                        <div style={{clear:"both"}}></div>
                    </div>
                    <div className="bottom">
                        <div 
                            className="button-group" 
                            style={{
                                width: 200, 
                                marginTop: 20,
                                marginLeft: 'auto', 
                                marginRight: 'auto', 
                                padding: 2
                            }}>
                            <div
                                className={this.state.isStarted ? 'active' : ''}
                                style={{borderRadius: 30, color: this.state.isStarted ? 'rgba(0, 135, 255, 1)' : 'rgba(255, 255, 255, 0.5)'}}
                                onClick={() => {
                                    if (!this.state.isStarted) {
                                        if (this.state.inputFiles.length > 0) {
                                            this.setState({
                                                isStarted: true,
                                                outputInfo: formatMessage({id: 'app.readingFile'}) + '...'
                                            });
                                            this.handleStartConvert();
                                        } else {
                                            message.error({
                                                className:'editor-message', 
                                                content: formatMessage({id: 'app.pleaseLoadFile'})
                                            });
                                        }
                                    }
                                }}>
                                { this.state.outputInfo || formatMessage({id: 'app.convert'}) }
                            </div>
                        </div>
                    </div>
                </div>
            </Modal>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(AudioConvertModal));