import * as React from "react";
import { connect } from "react-redux";
import { RouteComponentProps, withRouter } from "react-router";
import { Dropdown, Menu, Modal, Spin, Icon } from "antd";
import { formatMessage } from "../../AppRouter";
import { closePane, splitPane, closeTabsInPane, openFile, closeFile } from "../../actions/editorActions";
import { updateActivePanel } from "../../actions/settingActions";
import { Editor_Split_Type_Horizontal, Editor_Split_Type_Vertical } from "../../constants/EditorSplitType";
import { Editor_Panel_EditorPanel } from "../../constants/EditorPanelNames";
import { DEFAULT_ACTIVE_PANEL_COLOR } from "../../constants/DefaultSetting";
import { IPane, IPanes } from "../../interfaces/IPane";
import { IOpenFiles, IOpenFile } from './../../interfaces/IOpenfile';
import { updateActivePane, updateFile } from './../../actions/editorActions';
import MarkdownView from "../../components/fileView/MarkdownView";
import MarkdownEditor from "../../components/fileEditor/MarkdownEditor";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    activePanel: string|null|undefined;
    activePane: string|undefined;
    paneData: IPane;
    panes: IPanes;
    openfiles: IOpenFiles;
    closePane: Function;
    splitPane: Function;
    closeTabsInPane: Function;
    updateActivePanel: Function;
    updateActivePane: Function;
    openFile: Function;
    closeFile: Function;
    updateFile: Function;
}

const mapStateToProps = (state: any) => {
    return {
        activePanel: state.setting.activePanel,
        activePane: state.editor.activePane,
        panes: state.panes,
        openfiles: state.openfiles
    }
};

const mapDispatchTpProps = {
    closePane,
    splitPane,
    closeTabsInPane,
    updateActivePane,
    updateActivePanel,
    openFile,
    closeFile,
    updateFile
};


class PanePanel extends React.Component<IProps, IState> {

    generateEditorMultiPartStack = () => {
        return (
            <div className="editorMultiPartStack">
                <div className="content">
                    {this.generateEditorPartStack()}
                </div>
            </div>
        )
    }

    generateEditorPartStack = () => {
        return (
            <div className="editorPartStack">
                <div className="content">
                    {this.generateEditorPartStackTabsPanel()}
                    {this.generateEditorPartStackContentPanel()}
                </div>
            </div>
        );
    }

    generateEditorPartStackTabsPanel = () => {
        const tabsMenuData = [
            {type: 'item', name: formatMessage({id: 'app.paneClose'}), action: 'closePane'},
            {type: 'item', name: formatMessage({id: 'app.paneCloseAllTabs'}), action: 'closeAllTabsInPane'},
            {type: 'divider'},
            {type: 'item', name: formatMessage({id: 'app.paneSplitInTowRows'}), action: 'splitPaneInTowRows'},
            {type: 'item', name: formatMessage({id: 'app.paneSplitInTowColumns'}), action: 'splitPaneInTowColumns'},
        ];
        const tabsMenu = (
            <Menu
                className="editor-drop-menu tabs-menu"
                onClick={this.onTabsMenuClick}>
                {
                    tabsMenuData.map((item: any, index: number) => {
                        if (item.type === 'item') {
                            return (
                                <Menu.Item key={index} data-action={item.action}>
                                    <div>
                                        {
                                            item.icon && <div className="icon">{item.icon}</div>
                                        }
                                        <div className="text">{item.name}</div>
                                        {
                                            item.openFile && <div className="close"></div>
                                        }
                                    </div>
                                </Menu.Item>
                            );
                        } else if (item.type === 'divider') {
                            return <Menu.Divider key={index} />;
                        } else {
                            return null;
                        }
                    })
                }
            </Menu>
        );

        return (
            <div className="tabsPanel">
                <div className="content">
                    <div style={{
                        float: 'right',
                        position: 'relative',
                        width: 33,
                        height: 23,
                        overflow: 'hidden'
                    }}>
                        <Dropdown overlay={tabsMenu} trigger={['click']}>
                            <span className="iconfont">&#xe60c;</span>
                        </Dropdown>
                    </div>
                    {this.generateTabs()}
                </div>
            </div>
        );
    }

    generateEditorPartStackContentPanel = () => {
        return (
            <div className="contentPanel">
                <div className="content">
                    <div
                        style={{
                            position: 'absolute',
                            overflow: 'hidden',
                            left: 0,
                            top: 0,
                            width: '100%',
                            height: '100%'
                        }}>
                        { this.generateCurPage() }
                    </div>
                </div>
            </div>
        );
    }

    generateTabs = () => {
        return this.props.paneData.openFiles.map((path: string, index: number) => {
            let $openFile = this.props.openfiles[path];
            if ($openFile) {
                let className = 'session_btn btnclose';
                if (index === 0) {
                    className += ' firstbtn';
                } else if (index === this.props.paneData.openFiles.length - 1) {
                    className += ' lastbtn';
                }
                if (this.props.paneData.activeFile) {
                    if (path === this.props.paneData.activeFile) {
                        className += ' curbtn focus';
                    }
                    let extension: string|undefined = this.props.paneData.activeFile.split('.').pop();
                    if (extension) {
                        extension = extension.toLowerCase();
                    }
    
                    if ($openFile.editing) {
                        className += ' edit_view_tab';
                    } else {
                        if (extension === 'md') {
                            className += ' md_view_tab';
                        }
                    }
                }
                
                return (
                    <div
                        key={index}
                        onClick={this.onTabClick.bind(this, $openFile)}
                        className={className}>
                        <div className="tab_shadow"></div>
                        <div className="tab_middle">
                            <div className="sessiontab_title" title={$openFile.title}>
                                {($openFile.needUpload ? '* ' : '') + $openFile.title}
                            </div>
                            {
                                // this.props.paneData.openFiles.length > 1 &&
                                <strong onClick={this.onTabCloseClick.bind(this, $openFile)}></strong>
                            }
                        </div>
                    </div>
                );
            }
            return null;
        });
    };

    generateCurPage = () => {
        if (this.props.paneData.activeFile) {
            let $openFile = this.props.openfiles[this.props.paneData.activeFile];
            if ($openFile) {
                if (!$openFile.content) {
                    const antIcon = <Icon type="loading" style={{ fontSize: 24 }} spin />;
                    const percentage = $openFile.progress ? $openFile.progress.percentage : 0;
                    return <Spin indicator={antIcon} tip={`${formatMessage({id: "app.loading"})}...(${percentage})%`} />
                } else {
                    let extension: string|undefined = this.props.paneData.activeFile.split('.').pop();
                    if (extension) {
                        extension = extension.toLowerCase();
                    }
                    switch(extension) {
                        case 'md':
                            if ($openFile.editing) {
                                return <MarkdownEditor source={$openFile.content} onChange={this.onMarkdownEditorChange} />;
                            }
                            return <MarkdownView source={$openFile.content} />;
                    }
                }
            }
        }
        return null;
    };

    onMarkdownEditorChange = (e: any) => {
        if (this.props.paneData.activeFile) {
            let $openFile = this.props.openfiles[this.props.paneData.activeFile];
            if ($openFile) {
                $openFile.content = e.target.value;
                $openFile.needUpload = true;
                this.props.updateFile($openFile);
            }
        }
    };
    
    onTabsMenuClick = (e: any) => {
        if (e && e.domEvent && e.domEvent.stopPropagation) e.domEvent.stopPropagation();
        if (!this.props.paneData) return;
        let action: string = e.item.props['data-action'];
        if (action) {
            switch (action) {
                case 'closePane':
                    this.props.closePane(this.props.paneData.id);
                    break;
                case 'closeAllTabsInPane':
                    let closeTabs: number[] = [];
                    this.props.paneData.openFiles.map((path: string, index: number) => {
                        closeTabs.push(index);
                        return null;
                    });
                    if (closeTabs.length > 0) {
                        this.props.closeTabsInPane(closeTabs);
                    }
                    break;
                case 'splitPaneInTowRows':
                    this.props.splitPane(this.props.paneData.id, Editor_Split_Type_Vertical);
                    break;
                case 'splitPaneInTowColumns':
                    this.props.splitPane(this.props.paneData.id, Editor_Split_Type_Horizontal);
                    break;
            }
        }
    };

    onTabClick = (item: IOpenFile, e: any) => {
        this.props.openFile(item, this.props.paneData.id);
    };

    onTabCloseClick = (item: IOpenFile, e: any) => {
        if (e && e.stopPropagation) e.stopPropagation();
        if ((item.openNum == undefined || item.openNum == 1) && item.needUpload) {
            Modal.confirm({
                title: formatMessage({id: "app.closeFileConfirmTitle"}),
                content: formatMessage({id: "app.closeFileConfirmContent"}),
                okText: formatMessage({id: "app.ok"}),
                cancelText: formatMessage({id: "app.cancel"}),
                onOk: () => {
                    this.props.closeFile(item, this.props.paneData.id);
                }
            });
        } else {
            this.props.closeFile(item, this.props.paneData.id);
        }
    };

    openFileFromMatchParams = (matchParams: any) => {
        let zanejs = (window as any).zanejs;
        let category = matchParams['category'];
        let path: string|undefined = undefined;
        let title: string = '未命名';
        switch(category) {
            case 'article':
                path = decodeURIComponent(matchParams['path']);
                title = matchParams['title'] 
                    ? decodeURIComponent(matchParams['title'])
                    : zanejs.utils.basename(path);
                break;
        }
        if (path) {
            if (!zanejs.utils.isAbsoluteUrl(path)) {
                path = `${process.env.PUBLIC_URL}/${path}`;
            }
            this.props.openFile({title, path});
        }
    }

    componentDidMount() {
        if (this.props.activePane === this.props.paneData.id) {
            if (!this.props.paneData.activeFile) {
                this.openFileFromMatchParams(this.props.match.params);
            }
        }
    }

    render() {
        let paneName = this.props.paneData ? this.props.paneData.id : '';
        let panelName = Editor_Panel_EditorPanel + (this.props.paneData ? this.props.paneData.id : '');
        return (
            <div
                className="editorPanel"
                onClick={() => {
                    this.props.updateActivePane(paneName);
                    this.props.updateActivePanel(panelName);
                }}>
                <div
                    className="content"
                    style={{
                        zoom: 1,
                        /*backgroundColor: this.props.activePanel === panelName ? DEFAULT_ACTIVE_PANEL_COLOR : "transparent"*/
                    }}>
                    {this.generateEditorMultiPartStack()}
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(PanePanel));