import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { updateWidget } from "../../actions/settingActions";
import { initPaneMap, openFile } from "../../actions/editorActions";
import { Editor_Split_Type_Vertical } from "../../constants/EditorSplitType";
import { IPaneMap } from './../../interfaces/IEditor';
import { IPanes } from './../../interfaces/IPane';
import { formatMessage } from "../../AppRouter";
import PanePanel from "./PanePanel";
import SplitterLayout from "react-splitter-layout";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    paneMap: IPaneMap;
    panes: IPanes;
    initPaneMap: Function;
    openFile: Function;
}

const mapStateToProps = (state: any) => {
    return {
        paneMap: state.editor.paneMap,
        panes: state.panes
    }
};

const mapDispatchTpProps = {
    updateWidget,
    initPaneMap,
    openFile
};

class PerspectivePanel extends React.Component<IProps, IState> {

    generatePanePanel = (paneMap: IPaneMap|null) => {
        if (paneMap) {
            if (paneMap.primaryPane && paneMap.secondaryPane) {
                let vertical = paneMap.splitType == Editor_Split_Type_Vertical;
                return (
                    <SplitterLayout
                        primaryIndex={0}
                        vertical={vertical}
                        percentage={true}>
                        { this.generatePanePanel(paneMap.primaryPane) }
                        { this.generatePanePanel(paneMap.secondaryPane) }
                    </SplitterLayout>
                );
            } else {
                const pane = this.props.panes[paneMap.id];
                return <PanePanel paneData={pane} />
            }
        }
        return null;
    };

    componentDidMount() {
        if (!this.props.paneMap) {
            this.props.initPaneMap();
            this.props.openFile({
                title: formatMessage({id: 'app.about'}),
                editable: false,
                path:`${process.env.PUBLIC_URL}/about.md`
            });
        }
    }

    render() {
        return (
        <>{ this.generatePanePanel(this.props.paneMap) }</>
        );
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(PerspectivePanel));