const _style: any = {};

export function addHTMLElementStyle(element: HTMLElement, className: string, attributes: any) {
    let customStylesId = "customStyles";
    let head = document.head || document.getElementsByTagName('head')[0];
    let customStyles = document.getElementById(customStylesId) || document.createElement('style');
    customStyles.id = customStylesId;

    let tmpclassName = className.split(":")[0];
    var classNames = element.className.split(" ");
    if (classNames.indexOf(tmpclassName) === -1) {
        element.className += " " + tmpclassName;
    }
    
    if (!_style[className]) {
        _style[className] = {};
    }
    if (attributes) {
        Object.keys(attributes).map(key => {
            _style[className][key] = attributes[key];
        });
    }
    let cssText = '';
    Object.keys(_style).map($clssName => {
        cssText += `.${$clssName} {\n`;
        let styleObj = _style[$clssName];
        if (styleObj) {
            const lines = Object.keys(styleObj).map(property => `\t${property}: ${styleObj[property]};`);
            cssText += lines.join('\n') + '\n';
        }
        cssText += `}\n`;
    });
    customStyles.innerHTML = cssText;
    head.appendChild(customStyles);
};

export function addStyle(id: string, cssText: string) {
    // 创建一个style元素
    let style: any = document.createElement('style');
    // 获取head元素
    let head = document.head || document.getElementsByTagName('head')[0];
    // 这里必须显示设置style元素的type属性为text/css，否则在ie中不起作用
    style.type = 'text/css';
    // IE
    if (style.styleSheet) {
        let func = () => {
            // 防止IE中stylesheet数量超过限制而发生错误
            try {
                style.styleSheet.cssText = cssText;
            } catch(e) {

            }
        }
        //如果当前styleSheet还不能用，则放到异步中则行
        if (style.styleSheet.disabled) {
            setTimeout(func,10);
        } else {
            func();
        }
    }
    // w3c
    else {
        //w3c浏览器中只要创建文本节点插入到style元素中就行了
        let textNode = document.createTextNode(cssText);
        style.appendChild(textNode);
    }
    //把创建的style元素插入到head中
    head.appendChild(style);
}