import * as React from "react";
import { connect } from "react-redux";
import { RouteComponentProps, withRouter } from "react-router";
import { Modal, Spin, Input, Select, Upload, Button } from 'antd';
import { formatMessage } from "../../AppRouter";
import { Modal_Setting } from '../../constants/ModalNames';
import { updateModalName } from "../../actions/editorActions";
import { updateTheme } from "../../actions/settingActions";
import { ISite } from "../../interfaces/ISetting";
import InputNumber from "../../components/InputNumber";
import { addHTMLElementStyle } from "../../utils/addStyle";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    currentModalName: string|undefined;
    siteInfo: ISite|null|undefined;
    mainDockPanelStyle: any;
    updateModalName: Function;
    updateTheme: Function;
}

const mapStateToProps = (state: any) => {
    return {
        currentModalName: state.editor.currentModalName,
        siteInfo: state.setting.siteInfo,
        mainDockPanelStyle: state.setting.mainDockPanelStyle,
    }
};

const mapDispatchTpProps = {
    updateModalName,
    updateTheme
};


class SettingModal extends React.Component<IProps, IState> {

    private modalRootContainer: any = null;

    handleCancel = () => {
        this.props.updateModalName(null);
    };

    handleThemeBlurChange = (blur: number) => {
        if (this.props.siteInfo) {
            const theme = this.props.siteInfo.theme;
            theme.blur = blur;
            this.props.updateTheme(theme);
        }
    };

    handleThemeOpacityChange = (opacity: number) => {
        if (this.props.siteInfo) {
            const theme = this.props.siteInfo.theme;
            theme.opacity = opacity;
            this.props.updateTheme(theme);
        }
    };

    handleThemeImgChange = () => {

    };

    handleBlendModeChange = (blendMode: string) => {
        if (this.props.siteInfo) {
            const theme = this.props.siteInfo.theme;
            theme.backgroundBlendMode = blendMode;
            this.props.updateTheme(theme);
        }
    };

    handleThemeBgColorChange = () => {

    };

    _addHTMLElementStyle = () => {
        if (this.modalRootContainer) {
            addHTMLElementStyle(this.modalRootContainer, "modal-root-container::before", this.props.mainDockPanelStyle);
        } else {
            setTimeout(this._addHTMLElementStyle, 500);
        }
    };

    componentDidMount(): void {
        this._addHTMLElementStyle();
    }
    
    componentWillReceiveProps(nextProps: Readonly<IProps>, nextContext: any): void {
        if (this.modalRootContainer && this.props.mainDockPanelStyle != nextProps.mainDockPanelStyle) {
            addHTMLElementStyle(this.modalRootContainer, "modal-root-container::before", nextProps.mainDockPanelStyle);
        }
    }

    render() {
        let visible = this.props.currentModalName == Modal_Setting;
        let themeBlur = this.props.siteInfo && this.props.siteInfo.theme ? this.props.siteInfo.theme.blur : 20;
        let themeOpacity = this.props.siteInfo && this.props.siteInfo.theme ? this.props.siteInfo.theme.opacity : 0.2;
        let themeBlendMode = this.props.siteInfo && this.props.siteInfo.theme ? this.props.siteInfo.theme.backgroundBlendMode : "hue";
        let themeBgColor = this.props.siteInfo && this.props.siteInfo.theme ? this.props.siteInfo.theme.backgroundColor : "rgba(123, 123, 123, 0.35)";
        return (
            <Modal
                width={900}
                wrapClassName="editor-modal-wrap"
                title={<span>{formatMessage({id: 'app.settings'})}</span>}
                footer={null}
                visible={visible}
                onCancel={this.handleCancel}
                maskClosable={false}
                zIndex={999}>
                <div className="setting-container modal-root-container" ref={(value) => this.modalRootContainer = value}>
                    <div className="top"></div>
                    <div className="middle">
                        <div className="settingParam-item" style={{width: '81%'}}>
                            <div className="settingParam-item-left">
                                <span>{formatMessage({id: 'app.backgroundImage'})}</span>
                            </div>
                            <div className="settingParam-item-right">
                                <Upload multiple={false} 
                                        showUploadList={false}
                                        beforeUpload={(file, fileList) =>{
                                            
                                            return false;
                                        }}>
                                        <Button style={{width: 300}}>{formatMessage({id: 'app.clickAndSelectBackgroundImage'})}</Button>
                                </Upload>
                            </div>
                        </div>
                        <div style={{clear:"both"}}></div>
                    </div>
                    <div className="middle">
                        <div className="settingParam-item" style={{width: '40%'}}>
                            <div className="settingParam-item-left">
                                <span>{formatMessage({id: 'app.backgroundColor'})}</span>
                            </div>
                            <div className="settingParam-item-right">
                                <Input 
                                    onChange={this.handleThemeBgColorChange}
                                    style={{borderRadius: '0px 10px 10px 0px'}}
                                    value={themeBgColor} />
                            </div>
                        </div>
                        <div className="settingParam-item" style={{width: '40%'}}>
                            <div className="settingParam-item-left">
                                <span>{formatMessage({id: 'app.backgroundBlur'})}</span>
                            </div>
                            <div className="settingParam-item-right">
                                <InputNumber
                                    value={themeBlur}
                                    max={100}
                                    min={0}
                                    step={1}
                                    onChange={this.handleThemeBlurChange}
                                />
                            </div>
                        </div>
                        <div className="settingParam-item" style={{width: '40%'}}>
                            <div className="settingParam-item-left">
                                <span>{formatMessage({id: 'app.backgroundOpacity'})}</span>
                            </div>
                            <div className="settingParam-item-right">
                                <InputNumber
                                    value={themeOpacity}
                                    max={1}
                                    min={0}
                                    fixed={2}
                                    step={0.01}
                                    onChange={this.handleThemeOpacityChange}
                                />
                            </div>
                        </div>
                        <div className="settingParam-item" style={{width: '40%'}}>
                            <div className="settingParam-item-left">
                                <span>{formatMessage({id: 'app.backgroundBlendMode'})}</span>
                            </div>
                            <div className="settingParam-item-right">
                                <Select
                                    value={themeBlendMode} 
                                    onChange={this.handleBlendModeChange}
                                    style={{width: '100%'}}
                                    dropdownMatchSelectWidth={false}
                                    className="editor-select"
                                    dropdownClassName="editor-select-dropdown" >
                                    <Select.Option value="normal">normal</Select.Option>
                                    <Select.Option value="color">color</Select.Option>
                                    <Select.Option value="color-burn">color-burn</Select.Option>
                                    <Select.Option value="color-dodge">color-dodge</Select.Option>
                                    <Select.Option value="darken">darken</Select.Option>
                                    <Select.Option value="lighten">lighten</Select.Option>
                                    <Select.Option value="difference">difference</Select.Option>
                                    <Select.Option value="exclusion">exclusion</Select.Option>
                                    <Select.Option value="hard-light">hard-light</Select.Option>
                                    <Select.Option value="hue">hue</Select.Option>
                                    <Select.Option value="inherit">inherit</Select.Option>
                                    <Select.Option value="multiply">multiply</Select.Option>
                                    <Select.Option value="screen">screen</Select.Option>
                                    <Select.Option value="overlay">overlay</Select.Option>
                                    <Select.Option value="saturation">saturation</Select.Option>
                                    <Select.Option value="luminosity">luminosity</Select.Option>
                                </Select>
                            </div>
                        </div>
                        <div style={{clear:"both"}}></div>
                    </div>
                    <div className="bottom">
                        <div 
                            className="button-group" 
                            style={{
                                width: 200, 
                                marginTop: 20,
                                marginLeft: 'auto', 
                                marginRight: 'auto', 
                                padding: 2
                            }}>
                            <div
                                style={{borderRadius: 30, color: 'rgba(255, 255, 255, 0.5)'}}
                                onClick={() => {
                                    
                                }}>
                                {formatMessage({id: 'app.save'})}
                            </div>
                        </div>
                    </div>
                </div>
            </Modal>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(SettingModal));