export const getIconNameByLanguage = (language: string) => {
    let iconName = 'folder-git';
    if (language) {
        switch(language.toLowerCase()) {
            case "typeScript":  iconName = 'folder-typescript';     break;
            case "javascript":  iconName = 'folder-javascript';     break;
            case "python":      iconName = 'folder-python';         break;
            case "shell":       iconName = 'folder-src';            break;
            case "php":         iconName = 'folder-php';            break;
            case "css":         iconName = 'folder-css';            break;
        }
    }
    return iconName;
};